class Solution:
    def smallestEquivalentString(self, s1, s2, baseStr):
        adj = {chr(97 + i): set([chr(97 + i)]) for i in range(26)}
        for a, b in zip(s1, s2):
            adj[a].add(b)
            adj[b].add(a)
        rep = {}
        for c in (chr(97 + i) for i in range(26)):
            if c in rep:
                continue
            stack = [c]
            comp = []
            seen = set()
            while stack:
                x = stack.pop()
                if x in seen:
                    continue
                seen.add(x)
                comp.append(x)
                for y in adj[x]:
                    if y not in seen:
                        stack.append(y)
            mn = min(comp)
            for x in comp:
                rep[x] = mn
        return ''.join(rep[c] for c in baseStr)

