class Solution:
    def smallestEquivalentString(self, s1, s2, baseStr):
        parent = list(range(26))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if ra < rb:
                parent[rb] = ra
            else:
                parent[ra] = rb
        for a, b in zip(s1, s2):
            union(ord(a) - 97, ord(b) - 97)
        return ''.join(chr(find(ord(c) - 97) + 97) for c in baseStr)

